import{_ as a,o as n,c as e,ag as l}from"./chunks/framework.DXGyWiRo.js";const F=JSON.parse('{"title":"LinkedQL Integration Patterns","description":"","frontmatter":{},"headers":[],"relativePath":"guides/integration-patterns.md","filePath":"guides/integration-patterns.md"}'),o={name:"guides/integration-patterns.md"};function t(p,s,r,c,i,D){return n(),e("div",null,[...s[0]||(s[0]=[l(`<h1 id="linkedql-integration-patterns" tabindex="-1">LinkedQL Integration Patterns <a class="header-anchor" href="#linkedql-integration-patterns" aria-label="Permalink to &quot;LinkedQL Integration Patterns&quot;">​</a></h1><p>LinkedQL is designed to map directly to modern application architectures.</p><p>Instead of introducing separate systems for APIs, caching, synchronization, and local state, LinkedQL composes these concerns from a small set of primitives.</p><p>This page shows how those primitives combine into common integration patterns:</p><ul><li>direct database access</li><li>cross-runtime access over a boundary</li><li>local-first architectures with synchronization</li><li>worker-isolated and multi-context setups</li></ul><p>All patterns preserve the same database interface.</p><hr><h2 id="baseline-direct-database-access" tabindex="-1">Baseline: Direct Database Access <a class="header-anchor" href="#baseline-direct-database-access" aria-label="Permalink to &quot;Baseline: Direct Database Access&quot;">​</a></h2><p>Most applications start with a direct connection to a database:</p><blockquote><p><strong>App → Database</strong></p></blockquote><p>This is the conventional model where:</p><ul><li>the application and database run in reachable environments</li><li>queries are executed directly over a native protocol</li></ul><p>LinkedQL supports this through:</p><ul><li><code>PGClient</code></li><li><code>MySQLClient</code></li><li><code>MariaDBClient</code></li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="when-a-runtime-boundary-exists" tabindex="-1">When a Runtime Boundary Exists <a class="header-anchor" href="#when-a-runtime-boundary-exists" aria-label="Permalink to &quot;When a Runtime Boundary Exists&quot;">​</a></h2><p>As soon as your application crosses runtime boundaries, the problem changes.</p><p>Examples:</p><ul><li>the app runs in the browser, but the database is remote</li><li>the app needs to function offline</li><li>data must be shared across tabs, workers, or edge runtimes</li></ul><p>At this point, the challenge is no longer just querying.</p><p>It becomes:</p><ul><li>moving the database interface across boundaries</li><li>optionally running a database locally</li><li>synchronizing state between local and upstream systems</li></ul><p>LinkedQL addresses this with two primitives:</p><ul><li><strong><code>EdgeClient</code> ↔ <code>EdgeWorker</code></strong> — for crossing runtime or protocol boundaries</li><li><strong><code>FlashQL</code></strong> — for running a database locally</li></ul><p>These primitives can be used independently or composed into larger architectures.</p><hr><h2 id="core-primitives" tabindex="-1">Core Primitives <a class="header-anchor" href="#core-primitives" aria-label="Permalink to &quot;Core Primitives&quot;">​</a></h2><p>All patterns are composed from these two primitives:</p><ul><li><p><strong><code>EdgeClient</code> ↔ <code>EdgeWorker</code></strong><br> These represent two ends of a transport protocol. <code>EdgeClient</code> is the application-facing side of the boundary, and <code>EdgeWorker</code> is the runtime side that exposes a database over that boundary. (Full details in <a href="/guides/edge">Edge</a>).</p></li><li><p><strong><code>FlashQL</code></strong><br> The embedded database that enables local-first storage, sync, and federation when the database itself needs to live inside the application runtime. (Full details in <a href="/flashql">FlashQL</a>, <a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a>).</p></li></ul><p>Should you be new to the overall system, it helps to read this page alongside <a href="/overview">What Is LinkedQL</a>, <a href="/guides">Guides</a>, <a href="/lang">Language</a>, and <a href="/realtime">Realtime</a>.</p><hr><h2 id="the-patterns-by-use-case" tabindex="-1">The Patterns By Use Case <a class="header-anchor" href="#the-patterns-by-use-case" aria-label="Permalink to &quot;The Patterns By Use Case&quot;">​</a></h2><p>Choose your starting pattern based on the shape of your application:</p><ul><li><p>Need remote database access only</p><p>→ <strong>Pattern A: EdgeClient → Backend</strong><br> (<a href="#pattern-a-edgeclient--backend">Jump to section</a>)</p></li><li><p>Need local-first / offline-first behavior</p><p>→ <strong>Pattern B: FlashQL → Backend</strong><br> (<a href="#pattern-b-flashql--backend">Jump to section</a>)</p></li><li><p>Need local-first + worker isolation or multi-tab support</p><p>→ <strong>Pattern C: EdgeClient → FlashQL (Worker) → Backend</strong><br> (<a href="#pattern-c-edgeclient--flashql-worker--backend">Jump to section</a>)</p></li></ul><p>These patterns are composable—you can evolve from one to another without changing your application’s data model.</p><p>The patterns differ mainly in where the database lives, where the app lives, and whether the data layer must cross runtime boundaries, persist locally, or synchronize with upstream state.</p><hr><h2 id="pattern-a-edgeclient-→-backend" tabindex="-1">Pattern A: <code>EdgeClient → Backend</code> <a class="header-anchor" href="#pattern-a-edgeclient-→-backend" aria-label="Permalink to &quot;Pattern A: \`EdgeClient → Backend\`&quot;">​</a></h2><p>This is the <strong>remote-first</strong> pattern:</p><blockquote><p>the application runs in one runtime, such as the browser, edge, or another process. The database lives remotely</p></blockquote><p>The <a href="/guides/edge">EdgeClient</a> and <a href="/guides/edge">EdgeWorker</a> pair gives you the full LinkedQL contract across the boundary.</p><h3 id="on-the-application-side" tabindex="-1">On the Application Side <a class="header-anchor" href="#on-the-application-side" aria-label="Permalink to &quot;On the Application Side&quot;">​</a></h3><p><code>EdgeClient</code> serves as the database your application sees:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> result </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="on-the-backend" tabindex="-1">On the Backend <a class="header-anchor" href="#on-the-backend" aria-label="Permalink to &quot;On the Backend&quot;">​</a></h3><p>You setup your database and expose it to <code>EdgeClient</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> PGClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeWorker</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge-worker</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> PGClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  host</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">localhost</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  user</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">postgres</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  password</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">password</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  database</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">myapp</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> worker </span><span style="color:#89DDFF;">=</span><span style="color:#BABED8;"> EdgeWorker</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">httpWorker</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>You handle incoming operations in the specified route – <code>/api/db</code>:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">export</span><span style="color:#C792EA;"> async</span><span style="color:#C792EA;"> function</span><span style="color:#82AAFF;"> POST</span><span style="color:#89DDFF;">(</span><span style="color:#BABED8;font-style:italic;">request</span><span style="color:#89DDFF;">)</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#C792EA;">  const</span><span style="color:#BABED8;"> event</span><span style="color:#89DDFF;"> =</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> request</span><span style="color:#89DDFF;"> };</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  return</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> worker</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">handle</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">event</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h3 id="what-happens-across-the-boundary" tabindex="-1">What Happens Across the Boundary <a class="header-anchor" href="#what-happens-across-the-boundary" aria-label="Permalink to &quot;What Happens Across the Boundary&quot;">​</a></h3><ul><li><code>EdgeClient</code> forwards database operations</li><li><code>EdgeWorker</code> executes them against the upstream database</li><li>results are returned in the same shape as a local client</li></ul><h3 id="streaming-support-across-the-boundary" tabindex="-1">Streaming Support Across the Boundary <a class="header-anchor" href="#streaming-support-across-the-boundary" aria-label="Permalink to &quot;Streaming Support Across the Boundary&quot;">​</a></h3><p>Streaming works transparently across the Boundary:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> asyncIterable </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">stream</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name</span></span>
<span class="line"><span style="color:#C3E88D;">  FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  ORDER BY id</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">for</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> (</span><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> row </span><span style="color:#89DDFF;">of</span><span style="color:#BABED8;"> asyncIterable) </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#BABED8;">  console</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">log</span><span style="color:#F07178;">(</span><span style="color:#BABED8;">row</span><span style="color:#F07178;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><h3 id="live-queries-support-across-the-boundary" tabindex="-1">Live Queries Support Across the Boundary <a class="header-anchor" href="#live-queries-support-across-the-boundary" aria-label="Permalink to &quot;Live Queries Support Across the Boundary&quot;">​</a></h3><p>Live queries work transparently across the Boundary:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> liveResult </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;font-style:italic;"> await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT id, name FROM public.users</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#89DDFF;">,</span><span style="color:#89DDFF;"> {</span><span style="color:#F07178;"> live</span><span style="color:#89DDFF;">:</span><span style="color:#FF9CAC;"> true</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><p>For these capabilities, see the <a href="/guides/edge">Edge guide</a> for how backend capabilities map to protocol support.</p><hr><h2 id="pattern-b-flashql-→-backend" tabindex="-1">Pattern B: <code>FlashQL → Backend</code> <a class="header-anchor" href="#pattern-b-flashql-→-backend" aria-label="Permalink to &quot;Pattern B: \`FlashQL → Backend\`&quot;">​</a></h2><p>This is the <strong>local-first</strong> pattern:</p><blockquote><p>the database lives within the app or together in the same runtime. The server-side database becomes an upstream source of truth, replication partner, or synchronization peer.</p></blockquote><p>This distribution model fits modern apps that need local reads, local writes, resilience to network loss, or a database that can keep functioning while connectivity comes and goes.</p><h3 id="on-the-application-side-1" tabindex="-1">On the Application Side <a class="header-anchor" href="#on-the-application-side-1" aria-label="Permalink to &quot;On the Application Side&quot;">​</a></h3><p><a href="/flashql">FlashQL</a> becomes the actual database the application talks to. The upstream database optionally becomes an extension of the local database and the source of truth.</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#82AAFF;">  getUpstreamClient</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">    new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">connect</span><span style="color:#BABED8;">()</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="setting-up-sync" tabindex="-1">Setting Up Sync <a class="header-anchor" href="#setting-up-sync" aria-label="Permalink to &quot;Setting Up Sync&quot;">​</a></h3><p>You optionally want remote data as local tables – either as normal database views, materialized views, or realtime views. (Fully covered in <a href="/flashql/federation-and-sync">Federation, Materialization, and Sync</a>)</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">query</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">\`</span></span>
<span class="line"><span style="color:#C3E88D;">  CREATE REALTIME VIEW public.users AS</span></span>
<span class="line"><span style="color:#C3E88D;">  SELECT * FROM public.users</span></span>
<span class="line"><span style="color:#C3E88D;">  WITH (</span></span>
<span class="line"><span style="color:#C3E88D;">    replication_origin = &#39;postgres:primary&#39;,</span></span>
<span class="line"><span style="color:#C3E88D;">    write_policy = &#39;local_first&#39;</span></span>
<span class="line"><span style="color:#C3E88D;">  )</span></span>
<span class="line"><span style="color:#89DDFF;">\`</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="what-this-enables" tabindex="-1">What This Enables <a class="header-anchor" href="#what-this-enables" aria-label="Permalink to &quot;What This Enables&quot;">​</a></h3><ul><li>local querying and indexing</li><li>local writes</li><li>realtime synchronization</li><li>conflict-aware sync</li><li>one SQL surface for all data</li></ul><h3 id="sync-lifecycle" tabindex="-1">Sync Lifecycle <a class="header-anchor" href="#sync-lifecycle" aria-label="Permalink to &quot;Sync Lifecycle&quot;">​</a></h3><p>The application model stays small:</p><ul><li>you define remote data as local tables (views)</li><li><a href="/flashql">FlashQL</a> handles replication</li><li>on reconnect, you call <a href="/flashql/sync-api"><code>db.sync.sync()</code></a></li></ul><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">window</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">addEventListener</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">online</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#C792EA;"> async</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span><span style="color:#89DDFF;"> {</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">  await</span><span style="color:#BABED8;"> db</span><span style="color:#89DDFF;">.</span><span style="color:#BABED8;">sync</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">sync</span><span style="color:#F07178;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="pattern-c-edgeclient-→-flashql-worker-→-backend" tabindex="-1">Pattern C: <code>EdgeClient → FlashQL (Worker) → Backend</code> <a class="header-anchor" href="#pattern-c-edgeclient-→-flashql-worker-→-backend" aria-label="Permalink to &quot;Pattern C: \`EdgeClient → FlashQL (Worker) → Backend\`&quot;">​</a></h2><p>This pattern keeps the <strong>local-first database in a separate worker runtime</strong>.</p><p>The distribution model here is more layered:</p><blockquote><p>the UI lives in one runtime, the local database lives in a worker, and the upstream database still lives remotely behind another boundary.</p></blockquote><p>This is the pattern for applications that want local-first behavior, but also want to isolate database work from the main thread, centralize coordination, or share a worker-hosted <a href="/flashql">FlashQL</a> runtime across execution contexts.</p><h3 id="effective-execution-chain" tabindex="-1">Effective Execution Chain <a class="header-anchor" href="#effective-execution-chain" aria-label="Permalink to &quot;Effective Execution Chain&quot;">​</a></h3><p><code>UI EdgeClient → Worker EdgeWorker → FlashQL → Upstream EdgeClient → Backend EdgeWorker → Database</code></p><p>The UI still sees a single <code>db</code>.</p><p>This pattern composes the <a href="/guides/edge">Edge transport layer</a> with <a href="/flashql">FlashQL</a> and its <a href="/flashql/federation-and-sync">sync model</a>.</p><hr><h2 id="pattern-c1-dedicated-worker" tabindex="-1">Pattern C1: Dedicated Worker <a class="header-anchor" href="#pattern-c1-dedicated-worker" aria-label="Permalink to &quot;Pattern C1: Dedicated Worker&quot;">​</a></h2><p>This is the <strong>per-tab worker-local</strong> variant:</p><blockquote><p>each tab gets its own worker and its own local database runtime.</p></blockquote><p>That usually fits applications where isolation is preferred and cross-tab sharing is less important than keeping the UI thread free while still preserving the same <a href="/guides/edge">EdgeClient</a> contract in the UI.</p><h3 id="on-the-ui" tabindex="-1">On the UI <a class="header-anchor" href="#on-the-ui" aria-label="Permalink to &quot;On the UI&quot;">​</a></h3><p><code>EdgeClient</code> serves as the database your application sees:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">./db.worker.js</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">worker</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="in-the-web-worker" tabindex="-1">In the Web Worker <a class="header-anchor" href="#in-the-web-worker" aria-label="Permalink to &quot;In the Web Worker&quot;">​</a></h3><p><code>FlashQL</code> runs as the whole database or the first upstream database:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeWorker</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge-worker</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> FlashQL</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/flashql</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#89DDFF;font-style:italic;">import</span><span style="color:#89DDFF;"> {</span><span style="color:#BABED8;"> EdgeClient</span><span style="color:#89DDFF;"> }</span><span style="color:#89DDFF;font-style:italic;"> from</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">@linked-db/linked-ql/edge</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#BABED8;">EdgeWorker</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">webWorker</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  db</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#82AAFF;">    getUpstreamClient</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">      new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><hr><h2 id="pattern-c2-shared-worker" tabindex="-1">Pattern C2: Shared Worker <a class="header-anchor" href="#pattern-c2-shared-worker" aria-label="Permalink to &quot;Pattern C2: Shared Worker&quot;">​</a></h2><p>This is the <strong>shared worker-local</strong> variant:</p><blockquote><p>multiple tabs talk to one worker-hosted database for the origin.</p></blockquote><p>That distribution model is often the better fit when multi-tab state should stay aligned, synchronization should be centralized, and one shared <a href="/flashql">FlashQL</a> instance is more useful than several isolated ones.</p><h3 id="on-the-ui-1" tabindex="-1">On the UI <a class="header-anchor" href="#on-the-ui-1" aria-label="Permalink to &quot;On the UI&quot;">​</a></h3><p><code>EdgeClient</code> serves as the database your application sees:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#C792EA;">const</span><span style="color:#BABED8;"> db </span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">./db.js</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#F07178;">  type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">shared_worker</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="in-the-shared-worker" tabindex="-1">In the Shared Worker <a class="header-anchor" href="#in-the-shared-worker" aria-label="Permalink to &quot;In the Shared Worker&quot;">​</a></h3><p><code>FlashQL</code> runs as the whole database or the first upstream database:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight vp-code" tabindex="0"><code><span class="line"><span style="color:#BABED8;">EdgeWorker</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">sharedWorker</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#F07178;">  db</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> new</span><span style="color:#82AAFF;"> FlashQL</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#82AAFF;">    getUpstreamClient</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> ()</span><span style="color:#C792EA;"> =&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">      new</span><span style="color:#82AAFF;"> EdgeClient</span><span style="color:#BABED8;">(</span><span style="color:#89DDFF;">{</span><span style="color:#F07178;"> url</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">/api/db</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#F07178;"> type</span><span style="color:#89DDFF;">:</span><span style="color:#89DDFF;"> &#39;</span><span style="color:#C3E88D;">http</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;"> }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">  }</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#BABED8;">)</span><span style="color:#89DDFF;">;</span></span></code></pre></div><h3 id="why-shared-worker-is-often-ideal" tabindex="-1">Why Shared Worker Is Often Ideal <a class="header-anchor" href="#why-shared-worker-is-often-ideal" aria-label="Permalink to &quot;Why Shared Worker Is Often Ideal&quot;">​</a></h3><ul><li>one database per origin</li><li>consistent multi-tab state</li><li>centralized sync</li><li>reduced duplication of subscriptions</li></ul><hr><h2 id="choosing-a-pattern" tabindex="-1">Choosing a Pattern <a class="header-anchor" href="#choosing-a-pattern" aria-label="Permalink to &quot;Choosing a Pattern&quot;">​</a></h2><p>Start with:</p><ul><li><strong>Pattern A</strong> if you only need remote access and want <a href="/guides/edge">EdgeClient</a> to preserve the app-facing contract</li><li><strong>Pattern B</strong> if local-first is core to your product and <a href="/flashql/federation-and-sync">FlashQL sync</a> is part of the design</li><li><strong>Pattern C</strong> if you need local-first plus worker isolation or multi-tab coordination</li></ul><p>All patterns preserve the same database interface, so your application code remains stable as architecture evolves.</p><hr><h2 id="additional-reading" tabindex="-1">Additional Reading <a class="header-anchor" href="#additional-reading" aria-label="Permalink to &quot;Additional Reading&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">If you want to learn about...</th><th style="text-align:left;">Go to...</th></tr></thead><tbody><tr><td style="text-align:left;">the common application-facing methods across these patterns</td><td style="text-align:left;"><a href="/api">API</a></td></tr><tr><td style="text-align:left;">the broader LinkedQL set of guides</td><td style="text-align:left;"><a href="/guides">LinkedQL Guides</a></td></tr></tbody></table>`,119)])])}const d=a(o,[["render",t]]);export{F as __pageData,d as default};
